#include<bits/stdc++.h>
using namespace std;
int n,m,tot;
int fa[400010],col[200010],p[200010];
int find(int x)
{
    return (x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a==b)
    {
        return;
    }
    if(a<=n)
    {
        swap(a,b);
    }
    fa[a]=b;
    if(a<=n&&b<=n)
    {
        merge(a+n,b+n);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n*2;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        merge(x+n,y);
    }
    for(int i=1;i<=n;i++)
    {
        int x=find(i);
        if(!p[x])
        {
            p[x]=++tot;
        }
        col[i]=p[x];
    }
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",col[i]);
    }
    return 0;
}
